VALUES
  ('elementary-8b44517b-moex-00297', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '小趙致贈一幅題辭「功同良相」給好友，預祝他開業成功。他的好友最可能經營何種事業？', '["醫療", "餐飲", "金融", "補教"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00298', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列書信結尾問候語，使用最適當的是：', '["對師長用「叩請 金安」", "對親友晚輩用「即問 近好」", "對親友長輩用「即請 台安」", "對親友平輩用「敬請 鈞安」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00299', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「很少有書光靠封面設計就大賣。但另一方面，卻有很多書因為封面設計失敗而滯銷。」 關於這段文句的旨意，下列何者最適當？', '["書籍內容比起封面設計更為重要", "封面設計不良可能會讓好書滯銷", "封面設計與內容都出色才能暢銷", "封面設計的成敗決定銷量的高低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00300', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列選項「」中前後詞意相同的是：', '["「春秋」時節最適宜全家出遊／此人腹中自有「春秋」，對人總有褒貶", "這個社區的長者「早晚」都會在公園練氣功／無論是誰，「早晚」都得面對死亡", "張小姐是他的「紅顏」知己／「紅顏」棄軒冕，白首臥松雲——是李白對孟浩然的讚美", "在醫學院從事教學多年的李醫師已「桃李」滿門／名師「桃李」天下，一點都不令人意外"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00301', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句「」中的成語，使用最適當的是：', '["接待人員們「前倨後恭」，誠摯歡迎每位與會的嘉賓", "在這寒冷的天氣，樹林一片「枝葉扶疏」的蕭瑟景象", "飯店緊臨港灣，在頂樓可以俯瞰「滄海橫流」的美景", "這家商店的營運狀況已「江河日下」，不能跟以前相比"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00302', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句「」中的成語，使用最適當的是：', '["面對世事無常，不禁使人產生「曾經滄海」之嘆", "經過一番努力，他終於能「克紹箕裘」，光大門楣", "他向來精打細算，善用「買櫝還珠」的策略而致富", "網路上的諸多訊息，有可能是「爍石流金」的謠言，並非事實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00303', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句「」中的成語，使用最適當的是：', '["文藝創作不僅需要「天花亂墜」般的才華，同時也要持續不懈地努力，才有可能獲得賞識", "突發性的心血管疾病十分危急，需要急救人員「奮勇爭先」地施以緊急醫療，才有可能挽 回一命", "他面對別人的質疑總能維持「落落大方」的風度，即便對方言詞犀利，也依然能夠虛心接 受別人的建議", "演講時不僅講究臺風的穩健，更要有著「信口雌黃」的功力，才有辦法吸引到大家的目光， 獲得更多掌聲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00304', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「多年後我自己重讀《易經》，愈來愈相信這是一部實用於生命現場的書，它可能啟始於某 一個簡易的神祕公式，但真正的完成靠的卻是人的世故，有點像統計學，收集了人一次次刻 骨銘心的生命經驗和教訓編纂起來。它預言的堅實基礎來自厚厚一疊而非一次的過去，來自 人一再重複類似處境慢慢察覺出來的事物某種慣性和人心某種趨向，這每一種特定的處境， 都一定程度制約窄化了未來，引發著特定的變化乃至於其規律節奏，未來因此有一部分可推 演可猜測。」 根據上文，作者認為《易經》是一部實用於生命現場的書，最主要的原因是：', '["具神祕啟示性質，可占卜人世吉凶", "立足於經驗及人性，具一定準確度", "能推演吉凶，源於堅實的數學運算", "始於神祕公式，可信度被充分驗證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00305', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「投身到任何一個行業，只好埋頭苦幹。有人只看見和尚吃饅頭，沒看見和尚受戒，遂生羨 慕別人之心，以為自己這一行只有苦沒有樂。」 根據上文，下列何者最符合文意？', '["一分生意三分險", "問遍千家是行家", "做一行，怨一行", "道路各別，養家一般"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00306', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「傳話時要記得只傳達雙方領袖的合理意見，而不要把他們加鹽添醋的情緒語言也照樣傳 達。這樣就算談判沒有很成功，也在可以理解的範圍中，而不致成為老闆情緒挫折的替罪 羔羊。」 根據上文，傳話者經常被老闆視為替罪羔羊，最主要的原因是：', '["過度虛美的言辭", "明哲保身的態度", "傳達的方式欠妥", "傳遞的訊息有誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
